import api from "../components/api";
import { IUser } from "../types/types";
import { CheckEmailRes } from "../services/login/loginTypes";
import { getCookie } from "../utils/utils";

const loginService = async (jwt: string, token?: string): Promise<any> => {
  console.log('qaaa', token);
  const response = await api.post("/v1/session", {gt: token}, {
    headers: {
      'Authorization': `Bearer ${jwt}`,
    }
  });
  return response.data;
};

const checkEmailService = async (email: string): Promise<CheckEmailRes> => {
  const response = await api.get("/v1/user/check-email", { params: { email } });
  return response.data;
};

const getUserDataService = async (): Promise<IUser> => {
  const response = await api.get("/v1/user");
  return response.data;
};

const useUser = () => {
  const login = async (jwt: string, token?: string): Promise<boolean> => {
    return loginService(jwt, token)
      .then(() => {
        return true
      })
  }

  const checkEmail = async (email: string): Promise<boolean> => {
    return checkEmailService(email)
      .then((res: CheckEmailRes) => {
        return res.registered;
      })
      .catch((err) => {
        return false;
      })
  }

  const isLogged = (): boolean => {
    return getCookie('isLogged') === 'true' ? true : false;
  }

  const getUserFirstName = (): string => {
    return getCookie('firstName') || '';
  }

  const getUserDataFromApi = async (): Promise<IUser> => {
    if (isLogged() === false) {
      throw 'Usuário não logado';
    } else {
      return getUserDataService()
        .then((res: IUser) => {
          return res;
        })
    }
  }

  return { login, checkEmail, isLogged, getUserFirstName, getUserDataFromApi }
}
export default useUser;

