import { Box, Button, Container, Grid, Link, TextField, Typography } from '@mui/material';
import React, { useRef, useState } from "react";
import Layout from "../components/Layout";
import useUser from "../storage/useUser";
import ReCAPTCHA from "react-google-recaptcha";

export default function Contato() {
    const recaptchaRef = React.useRef() as any;

    const [formData, setFormData] = useState({
        nome: '',
        email: '',
        telefone: '',
        assunto: '',
        mensagem: '',
    })
    const { login } = useUser();

    const handleChange = (e: any) => {
        const { name, value } = e.target;
        setFormData({ ...formData, [name]: value });
    };

    const handleSubmit = async (e: any) => {
        e.preventDefault();
        let token;
        if (recaptchaRef && recaptchaRef.current) {
            token = await recaptchaRef?.current.executeAsync();
            console.log('foi async');
        }
        if (token) {
            alert("Verifique o reCAPTCHA");
        }
        else {
            console.log(token);
            console.log(formData);
        }
    };


    return (
        <Layout>
            <Container maxWidth="sm">
                <Box mt={5} mb={5}>
                    <form onSubmit={handleSubmit}>
                        <Grid container spacing={2}>
                            <Grid item xs={12}>
                                <Typography variant="h4" align="center" gutterBottom>
                                    Fale Conosco
                                </Typography>
                                <Typography variant="caption" display="block" gutterBottom>
                                    Estamos aqui para ajudar! Por favor, preencha o formulário abaixo com sua dúvida, sugestão ou qualquer outra questão. Nossa equipe entrará em contato em até um dia útil.
                                </Typography>
                            </Grid>
                            <Grid item xs={12} sm={12}>
                                <TextField
                                    fullWidth
                                    label="Nome"
                                    name="nome"
                                    value={formData.nome}
                                    onChange={handleChange}
                                    required
                                />
                            </Grid>
                            <Grid item xs={12} sm={6}>
                                <TextField
                                    fullWidth
                                    label="Email"
                                    type="email"
                                    name="email"
                                    value={formData.email}
                                    onChange={handleChange}
                                    required
                                />
                            </Grid>
                            <Grid item xs={12} sm={6}>
                                <TextField
                                    fullWidth
                                    label="Telefone (opcional)"
                                    name="telefone"
                                    value={formData.telefone}
                                    onChange={handleChange}
                                />
                            </Grid>
                            <Grid item xs={12}>
                                <TextField
                                    fullWidth
                                    label="Assunto"
                                    name="assunto"
                                    value={formData.assunto}
                                    onChange={handleChange}
                                    required
                                />
                            </Grid>
                            <Grid item xs={12}>
                                <TextField
                                    fullWidth
                                    label="Mensagem"
                                    multiline
                                    rows={4}
                                    inputProps={{ maxLength: 500 }}
                                    name="mensagem"
                                    value={formData.mensagem}
                                    onChange={handleChange}
                                    required
                                />
                                <Typography>
                                    {`${formData.mensagem.length}/500`}
                                </Typography>
                            </Grid>
                            <Grid item xs={12}>
                                <Typography variant="body2" gutterBottom>
                                    Ao enviar a mensagem, você concorda com a <Link href="/politica-de-privacidade">política de privacidade</Link>.
                                </Typography>
                            </Grid>
                            <Grid item xs={12}>
                                <ReCAPTCHA
                                    ref={recaptchaRef}
                                    size="invisible"
                                    sitekey="6LdeWzYpAAAAAL-JlF0oR3k0EkddqFZKfA9KYErw"
                                />
                            </Grid>

                            <Grid item xs={12}>
                                <Button type="submit" size="large" variant="contained" color="primary" fullWidth>
                                    Enviar mensagem
                                </Button>
                            </Grid>
                        </Grid>
                    </form>
                </Box>
            </Container>
        </Layout>
    );
}
